const AutocompleteItemText = forwardRef<HTMLSpanElement, ComponentProps<'span'>>(
  function AutocompleteItemText({ className, ...props }, ref) {
    return (
      <span
        ref={ref}
        data-slot="autocomplete-item-text"
        className={clsx(styles.itemText, className)}
        {...props}
      />
