const AutocompleteGroupLabel = forwardRef<
  ComponentRef<typeof AutocompletePrimitive.GroupLabel>,
  AutocompletePrimitive.GroupLabel.Props
>(function AutocompleteGroupLabel({ className, ...props }, ref) {
