@layer ui.components {
  .inputGroup {
    position: relative;
    display: flex;
    align-items: center;
    width: var(--autocomplete-width, 16rem);
    min-height: var(--autocomplete-control-height, var(--size-lg));
    padding-inline: var(--autocomplete-input-group-padding-x, 0);
    border: var(--autocomplete-border-width, var(--border-width-sm)) solid
      var(--autocomplete-border-color, var(--color-border));
    border-radius: var(--autocomplete-radius, var(--radius-md));
    background-color: var(--autocomplete-bg, var(--color-background));
    color: var(--autocomplete-color, var(--color-foreground));
    outline: var(
        --autocomplete-focus-ring-width,
        var(--autocomplete-border-width, var(--border-width-sm))
      )
      solid transparent;
    outline-offset: calc(
      var(
          --autocomplete-focus-ring-offset,
          var(--autocomplete-border-width, var(--border-width-sm))
        ) *
        -1
    );
    transition:
      border-color var(--transition-default),
      outline-color var(--transition-default);

    &:focus-within {
      border-color: var(--autocomplete-focus-ring-color, var(--color-ring));
      outline-color: var(--autocomplete-focus-ring-color, var(--color-ring));
    }

    &:has(
      > [data-slot='autocomplete-input'][data-disabled],
      > [data-slot='autocomplete-input']:disabled
    ) {
      opacity: var(--opacity-disabled);
    }
  }

  .input {
    box-sizing: border-box;
    width: 100%;
    min-width: 0;
    height: var(--autocomplete-control-height, var(--size-lg));
    margin: 0;
    border: 0;
    border-radius: inherit;
    padding-inline: var(--autocomplete-input-padding-x-start, 0.875rem)
      var(--autocomplete-input-padding-x-end, 0.875rem);
    background: transparent;
    color: inherit;
    font: inherit;
    outline: 0;

    &::placeholder {
      color: var(--autocomplete-input-placeholder-color, var(--color-muted-foreground));
    }
  }

  .inputGroup:has(> [data-slot='autocomplete-control-actions']) {
    & .input {
      padding-inline-end: var(--autocomplete-input-padding-x-end-with-actions, 3.25rem);
    }
  }

  .trigger,
  .clear {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--autocomplete-action-size, 1.5rem);
    height: var(--autocomplete-action-size, 1.5rem);
    flex-shrink: 0;
    margin: 0;
    padding: 0;
    border: 0;
    border-radius: var(--autocomplete-action-radius, var(--radius-sm));
    background: transparent;
    color: var(--autocomplete-icon-color, var(--color-muted-foreground));
    cursor: pointer;
    transition:
      background-color var(--transition-default),
      color var(--transition-default);

    &:hover:not(:disabled):not([data-disabled]) {
      background-color: var(--autocomplete-action-bg-hover, var(--color-muted));
      color: var(--autocomplete-action-color-hover, var(--color-foreground));
    }

    &:focus-visible {
      outline: var(
          --autocomplete-focus-ring-width,
          var(--autocomplete-border-width, var(--border-width-sm))
        )
        solid var(--autocomplete-focus-ring-color, var(--color-ring));
      outline-offset: var(
        --autocomplete-focus-ring-offset,
        var(--autocomplete-border-width, var(--border-width-sm))
      );
    }

    &:is(:disabled, [data-disabled]) {
      cursor: not-allowed;
    }
  }

  .icon {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--autocomplete-icon-size, 0.875rem);
    height: var(--autocomplete-icon-size, 0.875rem);
    flex-shrink: 0;
    color: var(--autocomplete-icon-color, var(--color-muted-foreground));
  }

  .iconSvg {
    width: var(--autocomplete-icon-svg-size, 1rem);
    height: var(--autocomplete-icon-svg-size, 1rem);
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    background-color: var(--autocomplete-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--autocomplete-backdrop-blur, 4px)));
    transition:
      opacity var(--autocomplete-backdrop-transition, var(--transition-default)),
      backdrop-filter var(--autocomplete-backdrop-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--autocomplete-backdrop-starting-opacity, 0);
      backdrop-filter: var(--autocomplete-backdrop-starting-blur, none);
    }

    &[data-ending-style] {
      opacity: var(--autocomplete-backdrop-ending-opacity, 0);
      backdrop-filter: var(--autocomplete-backdrop-ending-blur, none);
    }
  }

  .positioner {
    z-index: var(--z-popup);
    outline: 0;
  }

  .popup {
    box-sizing: border-box;
    width: var(--anchor-width);
    min-width: min(var(--anchor-width), var(--available-width));
    max-width: var(--available-width);
    max-height: min(var(--autocomplete-popup-max-height, 24rem), var(--available-height));
    overflow: visible;
    border: 0;
    border-radius: var(--autocomplete-radius, var(--radius-md));
    background-color: var(--autocomplete-popup-bg, var(--color-popover));
    color: var(--autocomplete-color, var(--color-popover-foreground));
    outline: var(--autocomplete-popup-border-width, var(--border-width-sm)) solid
      var(--autocomplete-popup-border-color, var(--color-border));
    box-shadow: var(--autocomplete-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);
    transition:
      opacity var(--autocomplete-popup-transition, var(--transition-default)),
      transform var(--autocomplete-popup-transition, var(--transition-default)),
      translate var(--autocomplete-popup-transition, var(--transition-default));

    &[data-starting-style] {
      opacity: var(--autocomplete-popup-starting-opacity, 0);
      translate: var(--autocomplete-popup-starting-translate-x, 0)
        var(--autocomplete-popup-starting-translate-y, 0);
      transform: scale(var(--autocomplete-popup-starting-scale, var(--scale-popup)));
    }

    &[data-ending-style] {
      opacity: var(--autocomplete-popup-ending-opacity, 0);
      translate: var(--autocomplete-popup-ending-translate-x, 0)
        var(--autocomplete-popup-ending-translate-y, 0);
      transform: scale(var(--autocomplete-popup-ending-scale, var(--scale-popup)));
    }

    &:has(> [data-slot='autocomplete-inline-input-container']) {
      --autocomplete-inline-input-container-height: calc(
        var(--autocomplete-control-height, var(--size-lg)) +
          var(--autocomplete-inline-input-container-padding-top, var(--spacing-2)) +
          var(--autocomplete-inline-input-container-padding-bottom, var(--spacing-2)) +
          var(--autocomplete-inline-input-divider-width, var(--border-width-sm))
      );
    }
  }

  .arrow {
    display: flex;
    color: var(--autocomplete-popup-bg, var(--color-popover));

    &[data-side='top'] {
      bottom: calc(var(--autocomplete-arrow-size, 8px) * -1);
      rotate: 180deg;
    }

    &[data-side='bottom'] {
      top: calc(var(--autocomplete-arrow-size, 8px) * -1);
      rotate: 0deg;
    }

    &[data-side='left'] {
      right: calc(var(--autocomplete-arrow-inline-offset, 13px) * -1);
      rotate: 90deg;
    }

    &[data-side='right'] {
      left: calc(var(--autocomplete-arrow-inline-offset, 13px) * -1);
      rotate: -90deg;
    }
  }

  .arrowSvg {
    display: block;
    width: var(--autocomplete-arrow-width, 1.25rem);
    height: var(--autocomplete-arrow-height, 0.625rem);
    overflow: visible;
  }

  .arrowFill {
    fill: currentColor;
  }

  .arrowOuterStroke {
    fill: var(
      --autocomplete-arrow-stroke-color,
      var(--autocomplete-popup-border-color, var(--color-border))
    );
  }

  .arrowInnerStroke {
    fill: var(--autocomplete-popup-bg, var(--color-popover));
  }

  .status {
    padding: 0;
    margin: 0;

    &:not(:empty) {
      display: flex;
      align-items: center;
      gap: var(--autocomplete-status-gap, var(--spacing-1));
      padding: var(--autocomplete-status-padding-y, 0.5rem)
        var(--autocomplete-status-padding-x, 0.75rem);
      border-bottom: var(--autocomplete-status-divider-width, var(--border-width-sm)) solid
        var(
          --autocomplete-status-divider-color,
          var(--autocomplete-popup-border-color, var(--color-border))
        );
      font-size: var(--autocomplete-status-font-size, var(--text-xs));
      line-height: var(--autocomplete-status-line-height, var(--line-height-text-xs));
      color: var(
        --autocomplete-status-color,
        var(--autocomplete-empty-color, var(--color-muted-foreground))
      );
    }
  }

  .empty {
    padding: 0;
    margin: 0;

    &:not(:empty) {
      padding: var(--autocomplete-empty-padding-y, 0.75rem)
        var(--autocomplete-empty-padding-x, 1rem);
      font-size: var(--autocomplete-empty-font-size, var(--text-sm));
      line-height: var(--autocomplete-empty-line-height, var(--line-height-text-sm));
      color: var(--autocomplete-empty-color, var(--color-muted-foreground));
    }
  }

  .list {
    box-sizing: border-box;
    max-height: min(
      var(--autocomplete-list-max-height, var(--autocomplete-popup-max-height, 24rem)),
      var(--available-height)
    );
    overflow-y: auto;
    overscroll-behavior: contain;
    padding-block: var(--autocomplete-list-padding-y, var(--popup-list-padding-y, 0.25rem));
    scroll-padding-block: var(
      --autocomplete-list-scroll-padding-y,
      var(--popup-list-padding-y, 0.25rem)
    );
    outline: 0;

    &[data-empty] {
      padding: 0;
    }

    [data-slot='autocomplete-inline-input-container'] + & {
      max-height: min(
        calc(
          var(--autocomplete-list-max-height, var(--autocomplete-popup-max-height, 24rem)) -
            var(--autocomplete-inline-input-container-height, 0px)
        ),
        calc(var(--available-height) - var(--autocomplete-inline-input-container-height, 0px))
      );
      padding-top: var(--autocomplete-inline-list-padding-top, 0.375rem);
      padding-bottom: var(--autocomplete-inline-list-padding-bottom, 0.5rem);
      scroll-padding-top: var(--autocomplete-inline-list-scroll-padding-top, 0.375rem);
      scroll-padding-bottom: var(--autocomplete-inline-list-scroll-padding-bottom, 0.5rem);
    }
  }

  .row {
    display: flex;
    align-items: center;
    gap: var(--autocomplete-row-gap, var(--spacing-1));
    padding-inline: var(--autocomplete-row-padding-x, var(--spacing-1));

    & > .item {
